def en_uzun_seri(sinyal_dizisi):
    if not sinyal_dizisi:
        return 0
    en = sayac = 1
    for i in range(1, len(sinyal_dizisi)):
        if sinyal_dizisi[i] == sinyal_dizisi[i - 1]:
            sayac += 1
            en = max(en, sayac)
        else:
            sayac = 1
    return en
